{"file_text": "using RecipeSharing.Models;

namespace RecipeSharing.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt", Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes over the dough.\n4. Tear mozzarella and distribute evenly.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti\nGuanciale (or pancetta)\nEggs\nPecorino Romano\nBlack pepper", Steps = "1. Cook spaghetti in salted boiling water.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated Pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat, add egg mixture, toss quickly.\n6. Serve immediately with extra cheese.", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-fry chicken until charred.\n3. Sauté garlic and ginger, add tomato sauce.\n4. Add garam masala, simmer 10 minutes.\n5. Stir in cream, add chicken pieces.\n6. Simmer 5 more minutes. Serve with rice.", AverageRating = 4.7, RatingCount = 15 },
        new Recipe { Id = 4, Title = "Vegetable Pad Thai", Category = "Asian", Ingredients = "Rice noodles\nTofu\nBean sprouts\nPeanuts\nLime\nTamarind paste\nFish sauce\nSugar\nGarlic\nEggs", Steps = "1. Soak rice noodles in warm water 30 minutes.\n2. Make sauce: tamarind, fish sauce, sugar.\n3. Stir-fry tofu until golden, set aside.\n4. Scramble eggs in wok, add noodles.\n5. Add sauce, toss until coated.\n6. Top with bean sprouts, peanuts, lime.", AverageRating = 4.3, RatingCount = 8 },
        new Recipe { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer.\n3. Warm tortillas in a dry pan.\n4. Assemble tacos with beef and toppings.\n5. Serve with salsa and sour cream.", AverageRating = 4.2, RatingCount = 10 },
        new Recipe { Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract", Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick.\n4. Fold chocolate mixture into eggs.\n5. Add flour gently.\n6. Pour into greased ramekins, bake 12 minutes.\n7. Invert onto plates, serve immediately.", AverageRating = 4.9, RatingCount = 25 },
    };

    private readonly List<RecipeCategory> _categories = new()
    {
        new RecipeCategory { Name = "Italian", Description = "Classic pasta, pizza, and Mediterranean flavors", Icon = "🍝" },
        new RecipeCategory { Name = "Indian", Description = "Rich curries, aromatic spices, and tandoori dishes", Icon = "🍛" },
        new RecipeCategory { Name = "Asian", Description = "Stir-fries, noodles, and bold umami flavors", Icon = "🥢" },
        new RecipeCategory { Name = "Mexican", Description = "Tacos, burritos, and vibrant salsas", Icon = "🌮" },
        new RecipeCategory { Name = "Desserts", Description = "Sweet treats, cakes, and indulgent delights", Icon = "🍰" },
    };

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void RateRecipe(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null)
        {
            var totalRating = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = (totalRating + rating) / recipe.RatingCount;
        }
    }
}
