@page "/"
@using RecipeSharing.Services

<PageTitle>Recipe Sharing Community</PageTitle>

<div class="container">
    <div class="text-center my-5">
        <h1>🍳 Recipe Sharing Community</h1>
        <p class="lead">Discover and share delicious recipes from around the world</p>
    </div>

    <h2 class="mb-4">Browse by Category</h2>
    <div class="row">
        @foreach (var category in _categories)
        {
            <div class="col-md-4 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body text-center">
                        <div style="font-size: 3rem;">@category.Icon</div>
                        <h5 class="card-title mt-2">@category.Name</h5>
                        <p class="card-text text-muted">@category.Description</p>
                        <a href="/category/@category.Name" class="btn btn-outline-primary">Browse Recipes</a>
                    </div>
                </div>
            </div>
        }
    </div>

    <div class="text-center mt-4 mb-5">
        <a href="/submit" class="btn btn-success btn-lg">📝 Submit Your Recipe</a>
    </div>
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<RecipeSharing.Models.RecipeCategory> _categories = new();

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }
}

@page "/category/{CategoryName}"
@using RecipeSharing.Services
@using RecipeSharing.Models

<PageTitle>@CategoryName Recipes</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1>@_icon @CategoryName Recipes</h1>

    @if (_recipes.Any())
    {
        <div class="row">
            @foreach (var recipe in _recipes)
            {
                <div class="col-md-6 mb-4">
                    <div class="card h-100 shadow-sm">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">
                                <span class="text-warning">@GetStars(recipe.AverageRating)</span>
                                <small class="text-muted">(@recipe.RatingCount ratings)</small>
                            </p>
                            <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
    else
    {
        <div class="alert alert-info">No recipes found in this category yet.</div>
    }
</div>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<Recipe> _recipes = new();
    private string _icon = "";

    protected override void OnInitialized()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
        var category = RecipeService.GetCategories().FirstOrDefault(c => c.Name.Equals(CategoryName, StringComparison.OrdinalIgnoreCase));
        _icon = category?.Icon ?? "📖";
    }

    private string GetStars(double rating)
    {
