<PageTitle>Submit a Recipe</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1>📝 Submit Your Recipe</h1>
    <p class="text-muted">Share your favorite recipe with the community!</p>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <strong>Recipe submitted successfully!</strong> Your recipe "@_title" has been added.
            <a href="/" class="alert-link">Back to Home</a>
        </div>
    }
    else
    {
        <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="recipeForm">
            <div class="row">
                <div class="col-md-8">
                    <div class="mb-3">
                        <label for="title" class="form-label">Recipe Title</label>
                        <InputText id="title" @bind-Value="_title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                    </div>

                    <div class="mb-3">
                        <label for="category" class="form-label">Category</label>
                        <InputSelect id="category" @bind-Value="_category" class="form-select">
                            <option value="">-- Select Category --</option>
                            @foreach (var cat in _categories)
                            {
                                <option value="@cat.Name">@cat.Icon @cat.Name</option>
                            }
                        </InputSelect>
                    </div>

                    <div class="mb-3">
                        <label for="ingredients" class="form-label">Ingredients</label>
                        <InputTextArea id="ingredients" @bind-Value="_ingredients" class="form-control" rows="6" placeholder="One ingredient per line" />
                    </div>

                    <div class="mb-3">
                        <label for="steps" class="form-label">Steps</label>
                        <InputTextArea id="steps" @bind-Value="_steps" class="form-control" rows="8" placeholder="Describe each step on a new line" />
                    </div>

                    <button type="submit" class="btn btn-success" disabled="@(!IsValid())">Submit Recipe</button>
                </div>
            </div>
        </EditForm>
    }
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private string _title = "";
    private string _category = "";
    private string _ingredients = "";
    private string _steps = "";
    private bool _submitted = false;
    private List<RecipeCategory> _categories = new();

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private bool IsValid() =>
        !string.IsNullOrWhiteSpace(_title) &&
        !string.IsNullOrWhiteSpace(_category) &&
        !string.IsNullOrWhiteSpace(_ingredients) &&
        !string.IsNullOrWhiteSpace(_steps);

    private void HandleSubmit()
    {
        if (!IsValid()) return;

        var recipe = new Recipe
        {
            Title = _title,
            Category = _category,
            Ingredients = _ingredients,
            Steps = _steps,
            AverageRating = 0,
            RatingCount = 0
        };

        RecipeService.AddRecipe(recipe);
        _submitted = true;
    }
}
