@page "/recipe/{Id:int}"
@using RecipeSharing.Services
@using RecipeSharing.Models

<PageTitle>@(_recipe?.Title ?? "Recipe")</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (_recipe is not null)
            {
                <li class="breadcrumb-item"><a href="/category/@_recipe.Category">@_recipe.Category</a></li>
                <li class="breadcrumb-item active">@_recipe.Title</li>
            }
        </ol>
    </nav>

    @if (_recipe is null)
    {
        <div class="alert alert-warning">Recipe not found.</div>
    }
    else
    {
        <h1>@_recipe.Title</h1>
        <p class="text-muted">Category: @_recipe.Category</p>

        <div class="row">
            <div class="col-md-4">
                <div class="card mb-4">
                    <div class="card-header"><strong>🥘 Ingredients</strong></div>
                    <ul class="list-group list-group-flush">
                        @foreach (var ingredient in _recipe.Ingredients.Split('\n'))
                        {
                            <li class="list-group-item">@ingredient</li>
                        }
                    </ul>
                </div>
            </div>
            <div class="col-md-8">
                <div class="card mb-4">
                    <div class="card-header"><strong>📋 Steps</strong></div>
                    <div class="card-body">
                        @foreach (var step in _recipe.Steps.Split('\n'))
                        {
                            <p>@step</p>
                        }
                    </div>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h5>Rate this Recipe</h5>
                <p class="text-muted">
                    Average: @_recipe.AverageRating.ToString("F1") / 5
                    (@_recipe.RatingCount ratings)
                </p>
                <StarRating RecipeId="_recipe.Id" @rendermode="InteractiveServer" />
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe? _recipe;

    protected override void OnInitialized()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@using RecipeSharing.Services
@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              style="cursor: pointer; font-size: 1.5rem;">
            @(star <= _selectedRating ? "★" : "☆")
        </span>
    }
    @if (_submitted)
    {
        <span class="ms-2 text-success">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private int _selectedRating = 0;
    private bool _submitted = false;

    private void Rate(int rating)
    {
        _selectedRating = rating;
        RecipeService.RateRecipe(RecipeId, rating);
        _submitted = true;
    }
}

